svg.script:

(function() {
  var frame = document.getElementById("f");

  // Fetch the main index.html of the group chat
  fetch('./index.html')
    .then(function(r) {
      if (!r.ok) throw new Error("Could not load app");
      return r.text();
    })
    .then(function(html) {
      // We need to adjust relative paths because the Blob URL will have a different origin/base
      // However, since we are loading it via an iframe, we might just want to set src directly if we can
      // But the user wants the "injection" feel, so we'll use a Blob.

      // Note: For relative scripts/css to work, we'd normally need to inject a <base> tag
      var dir = window.location.href.substring(0, window.location.href.lastIndexOf('/') + 1);
      var baseTag = '<base href="' + dir + '">';
      var finalHtml = html.replace('<head>', '<head>' + baseTag);

      var blob = new Blob([finalHtml], { type: "text/html" });
      frame.src = URL.createObjectURL(blob);

      // Update Title
      document.title = "Westcord";
    })
    .catch(function(err) {
      console.error(err);
      // Fallback or error message
      frame.contentDocument.body.innerHTML = "<h1 style='color:white; font-family:sans-serif; text-align:center; margin-top:20%;'>Failed to load Westcord</h1>";
    });
}());
